import json
import math
import os
import re
import struct
from collections import defaultdict, deque

SUPPLIER_FILES = [f"supplier_{i:03d}.stl" for i in range(1, 21)]


def is_binary_stl(path):
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        return False
    tri_count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + tri_count * 50
    if expected == len(data):
        return True
    head = data[:256].lstrip()
    if head.startswith(b'solid'):
        return False
    return True


def parse_ascii_stl(path):
    with open(path, 'r', encoding='utf-8', errors='ignore') as f:
        text = f.read()
    facet_pattern = re.compile(
        r'facet\s+normal\s+([^\s]+)\s+([^\s]+)\s+([^\s]+)\s+outer\s+loop\s+'
        r'vertex\s+([^\s]+)\s+([^\s]+)\s+([^\s]+)\s+'
        r'vertex\s+([^\s]+)\s+([^\s]+)\s+([^\s]+)\s+'
        r'vertex\s+([^\s]+)\s+([^\s]+)\s+([^\s]+)\s+'
        r'endloop\s+endfacet',
        re.IGNORECASE | re.MULTILINE
    )
    triangles = []
    for m in facet_pattern.finditer(text):
        nums = list(map(float, m.groups()))
        normal = tuple(nums[0:3])
        v1 = tuple(nums[3:6])
        v2 = tuple(nums[6:9])
        v3 = tuple(nums[9:12])
        triangles.append((normal, (v1, v2, v3)))
    return triangles


def parse_binary_stl(path):
    triangles = []
    with open(path, 'rb') as f:
        data = f.read()
    tri_count = struct.unpack('<I', data[80:84])[0]
    offset = 84
    for _ in range(tri_count):
        if offset + 50 > len(data):
            break
        vals = struct.unpack('<12fH', data[offset:offset+50])
        normal = tuple(vals[0:3])
        v1 = tuple(vals[3:6])
        v2 = tuple(vals[6:9])
        v3 = tuple(vals[9:12])
        triangles.append((normal, (v1, v2, v3)))
        offset += 50
    return triangles


def parse_stl(path):
    return parse_binary_stl(path) if is_binary_stl(path) else parse_ascii_stl(path)


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])


def cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )


def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]


def norm(a):
    return math.sqrt(dot(a, a))


def qv(v, eps=1e-6):
    return tuple(int(round(c/eps)) for c in v)


def validate(path):
    try:
        triangles = parse_stl(path)
    except Exception:
        return False, 'parse_error'
    if not triangles:
        return False, 'parse_error'

    edge_to_faces = defaultdict(list)
    oriented_edges = []
    face_normals_ok = True
    degenerate = False
    signed_volume = 0.0

    for fi, (declared_normal, verts) in enumerate(triangles):
        v1, v2, v3 = verts
        e1 = sub(v2, v1)
        e2 = sub(v3, v1)
        cn = cross(e1, e2)
        area2 = norm(cn)
        if area2 <= 1e-12:
            degenerate = True
        else:
            dn = norm(declared_normal)
            if dn > 1e-12:
                if dot(cn, declared_normal) < 0:
                    face_normals_ok = False
        signed_volume += dot(v1, cross(v2, v3)) / 6.0

        q1, q2, q3 = qv(v1), qv(v2), qv(v3)
        face_edges = [(q1, q2), (q2, q3), (q3, q1)]
        oriented_edges.append(face_edges)
        for a, b in face_edges:
            key = tuple(sorted((a, b)))
            edge_to_faces[key].append((fi, (a, b)))

    if degenerate:
        return False, 'degenerate_triangle'

    for key, uses in edge_to_faces.items():
        if len(uses) != 2:
            return False, 'non_manifold_or_open_edges'
        (f1, e1), (f2, e2) = uses
        if e1 == e2:
            return False, 'inverted_normals'

    adjacency = defaultdict(list)
    for key, uses in edge_to_faces.items():
        (f1, e1), (f2, e2) = uses
        same_dir = (e1 == e2)
        adjacency[f1].append((f2, not same_dir))
        adjacency[f2].append((f1, not same_dir))

    assigned = {}
    for start in range(len(triangles)):
        if start in assigned:
            continue
        assigned[start] = 1
        dq = deque([start])
        while dq:
            f = dq.popleft()
            for nb, should_flip_relation in adjacency[f]:
                want = assigned[f] * (-1 if should_flip_relation else 1)
                if nb in assigned:
                    if assigned[nb] != want:
                        return False, 'inverted_normals'
                else:
                    assigned[nb] = want
                    dq.append(nb)

    if not face_normals_ok:
        return False, 'inverted_normals'
    if abs(signed_volume) <= 1e-9:
        return False, 'zero_volume'
    return True, None


results = []
for path in SUPPLIER_FILES:
    valid, reason = validate(path)
    item = {'file': path, 'valid': valid}
    if not valid:
        item['reason'] = reason
    results.append(item)

with open('validation_report.json', 'w', encoding='utf-8') as f:
    json.dump({'results': results}, f)

print(json.dumps({'results': results}, indent=2))

